#include <bits/stdc++.h>using namespace std; // Type Aliases using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>;using pll = pair<long long, long long>;using vpll = vector<pair<long long, long long>>;using vpii = vector<pair<int, int>>; // Constantsconst ll MOD = 1e9 + 7; const ll INF = 1e18;   // Greatest Common Divisorll gcd(ll a, ll b) { return b == 0 ? a : gcd(b, a % b); } // Least Common Multiplell lcm(ll a, ll b) { return (a / gcd(a, b)) * b; } // Binary Exponentiation: (a^b) % m in O(log b)ll binpow(ll a, ll b, ll m = MOD) {    a %= m;    ll res = 1;    while (b > 0) {        if (b & 1) res = res * a % m;        a = a * a % m;        b >>= 1;    }    return res;} // Modular Inverse: Used for (a/b) % MODll modInverse(ll n, ll m = MOD) { return binpow(n, m - 2, m); } // --- Debugging Utility (Local Only) ---#ifndef ONLINE_JUDGE#define debug(x) cerr << #x <<" "; _print(x); cerr << endl;#else#define debug(x)#endif void _print(ll t) {cerr << t;}void _print(int t) {cerr << t;}void _print(string t) {cerr << t;}void _print(char t) {cerr << t;}void _print(double t) {cerr << t;}template <class T, class V> void _print(pair <T, V> p);template <class T> void _print(vector <T> v);template <class T, class V> void _print(pair <T, V> p) {cerr << "{"; _print(p.first); cerr << ","; _print(p.second); cerr << "}";}template <class T> void _print(vector <T> v) {cerr << "[ "; for (T i : v) {_print(i); cerr << " "; } cerr << "]";}  void solve() {    ll n;    cin >> n;    ll left=1;    ll right=n-1;    for(int i=2;i*i<=n;i++){        if(n%i==0){            left=n/i;            right=n-left;            break;        }    }    cout<<left<<" "<<right<<endl;                    }int main() {    ios_base::sync_with_stdio(false);    cin.tie(NULL);    cout.tie(NULL);    int T = 1;    if (cin >> T) {        while (T--) {            solve();        }    } else {        solve();    }    return 0;}